INSERT INTO `ACT_GE_BYTEARRAY` VALUES ('10002',1,'declaration_process_111.bpmn20.xml','10001',_binary '<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<definitions xmlns=\"http://www.omg.org/spec/BPMN/20100524/MODEL\" \n             xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\" \n             xmlns:xsd=\"http://www.w3.org/2001/XMLSchema\" \n             xmlns:flowable=\"http://flowable.org/bpmn\" \n             xmlns:bpmndi=\"http://www.omg.org/spec/BPMN/20100524/DI\"\n             xmlns:omgdc=\"http://www.omg.org/spec/DD/20100524/DC\"\n             xmlns:omgdi=\"http://www.omg.org/spec/DD/20100524/DI\"\n             targetNamespace=\"http://www.flowable.org/processdef\">\n  <process id=\"declarationProcess\" name=\"鐢虫姤瀹℃壒鍏ㄧ敓鍛藉懆鏈熸祦绋媆" isExecutable=\"true\">\n    \n    <!-- 1. 鎻愪氦涓庡垵瀹?-->\n    <startEvent id=\"startEvent1\" name=\"鍚姩鐢虫姤\" flowable:initiator=\"starterId\"></startEvent>\n    \n    <userTask id=\"deptAudit\" name=\"閮ㄩ棬鍒濆\" flowable:candidateGroups=\"DEPT_MANAGER\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\"></flowable:taskListener>\n      </extensionElements>\n    </userTask>\n    \n    <exclusiveGateway id=\"gw1\" name=\"鍒濆缁撴灉\"></exclusiveGateway>\n    \n    <!-- 2. 鍚堝悓鐢熸垚涓庡畾閲戦樁娈?-->\n    <serviceTask id=\"genContractTask\" name=\"鑷姩鐢熸垚鍏ㄥ鍗曡瘉\" flowable:delegateExpression=\"${declarationServiceTask}\"></serviceTask>\n    \n    <userTask id=\"depositPayment\" name=\"涓婁紶瀹氶噾鍑瘉\" flowable:assignee=\"${starterId}\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\"></flowable:taskListener>\n      </extensionElements>\n    </userTask>\n\n    <userTask id=\"depositAudit\" name=\"璐㈠姟纭瀹氶噾\" flowable:candidateGroups=\"FINANCE_MANAGER\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\"></flowable:taskListener>\n      </extensionElements>\n    </userTask>\n    \n    <exclusiveGateway id=\"gw2\" name=\"瀹氶噾瀹℃牳缁撴灉\"></exclusiveGateway>\n    \n    <!-- 3. 灏炬涓庣粨鏉熼樁娈?-->\n    <userTask id=\"balancePayment\" name=\"涓婁紶灏炬鍑瘉\" flowable:assignee=\"${starterId}\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\"></flowable:taskListener>\n      </extensionElements>\n    </userTask>\n\n    <userTask id=\"balanceAudit\" name=\"璐㈠姟纭灏炬\" flowable:candidateGroups=\"FINANCE_MANAGER\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\"></flowable:taskListener>\n      </extensionElements>\n    </userTask>\n    \n    <exclusiveGateway id=\"gw3\" name=\"灏炬瀹℃牳缁撴灉\"></exclusiveGateway>\n\n    <!-- 4. 鎻愯揣鍗曚笌缁撴潫闃舵 -->\n    <userTask id=\"pickupListUpload\" name=\"涓婁紶鎻愯揣鍗昞" flowable:assignee=\"${starterId}\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\"></flowable:taskListener>\n      </extensionElements>\n    </userTask>\n\n    <userTask id=\"pickupListAudit\" name=\"璐㈠姟纭鎻愯揣鍗昞" flowable:candidateGroups=\"FINANCE_MANAGER\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\"></flowable:taskListener>\n      </extensionElements>\n    </userTask>\n    \n    <exclusiveGateway id=\"gw4\" name=\"鎻愯揣鍗曞鏍哥粨鏋淺"></exclusiveGateway>\n    \n    <endEvent id=\"endEvent1\" name=\"娴佺▼瀹屾垚\">\n      <extensionElements>\n        <flowable:executionListener event=\"end\" delegateExpression=\"${declarationTaskListener}\"></flowable:executionListener>\n      </extensionElements>\n    </endEvent>\n    \n    <!-- 椹冲洖澶勭悊 -->\n    <userTask id=\"rejectHandler\" name=\"椹冲洖淇敼\" flowable:assignee=\"${starterId}\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\"></flowable:taskListener>\n      </extensionElements>\n    </userTask>\n\n    <!-- 杩炴帴绾?-->\n    <sequenceFlow id=\"f1\" sourceRef=\"startEvent1\" targetRef=\"deptAudit\"></sequenceFlow>\n    <sequenceFlow id=\"f2\" sourceRef=\"deptAudit\" targetRef=\"gw1\"></sequenceFlow>\n    <sequenceFlow id=\"f3\" name=\"閫氳繃\" sourceRef=\"gw1\" targetRef=\"genContractTask\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${approved == true}</conditionExpression>\n    </sequenceFlow>\n    <sequenceFlow id=\"f4\" name=\"椹冲洖\" sourceRef=\"gw1\" targetRef=\"rejectHandler\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${approved == false}</conditionExpression>\n    </sequenceFlow>\n    \n    <sequenceFlow id=\"f5\" sourceRef=\"genContractTask\" targetRef=\"depositPayment\"></sequenceFlow>\n    <sequenceFlow id=\"f5_1\" sourceRef=\"depositPayment\" targetRef=\"depositAudit\"></sequenceFlow>\n    <sequenceFlow id=\"f6\" sourceRef=\"depositAudit\" targetRef=\"gw2\"></sequenceFlow>\n    \n    <sequenceFlow id=\"f7\" name=\"閫氳繃\" sourceRef=\"gw2\" targetRef=\"balancePayment\">\n       <conditionExpression xsi:type=\"tFormalExpression\">${approved == true}</conditionExpression>\n    </sequenceFlow>\n    <sequenceFlow id=\"f8\" name=\"椹冲洖\" sourceRef=\"gw2\" targetRef=\"depositPayment\">\n       <conditionExpression xsi:type=\"tFormalExpression\">${approved == false}</conditionExpression>\n    </sequenceFlow>\n    \n    <sequenceFlow id=\"f8_1\" sourceRef=\"balancePayment\" targetRef=\"balanceAudit\"></sequenceFlow>\n    <sequenceFlow id=\"f9\" sourceRef=\"balanceAudit\" targetRef=\"gw3\"></sequenceFlow>\n    \n    <sequenceFlow id=\"f10\" name=\"閫氳繃\" sourceRef=\"gw3\" targetRef=\"pickupListUpload\">\n       <conditionExpression xsi:type=\"tFormalExpression\">${approved == true}</conditionExpression>\n    </sequenceFlow>\n    <sequenceFlow id=\"f11\" name=\"椹冲洖\" sourceRef=\"gw3\" targetRef=\"balancePayment\">\n       <conditionExpression xsi:type