ntation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\" />\n      </extensionElements>\n    </userTask>\n    <endEvent id=\"endEvent1\" name=\"娴佺▼瀹屾垚\">\n      <extensionElements>\n        <flowable:executionListener event=\"end\" delegateExpression=\"${declarationTaskListener}\" />\n      </extensionElements>\n    </endEvent>\n    <sequenceFlow id=\"f1\" sourceRef=\"startEvent1\" targetRef=\"genContractTaskSmall\" />\n    <sequenceFlow id=\"f2\" sourceRef=\"deptAudit\" targetRef=\"gw1\" />\n    <sequenceFlow id=\"f3_pass\" name=\"閫氳繃\" sourceRef=\"gw1\" targetRef=\"genContractTask\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${approved == true}</conditionExpression>\n    </sequenceFlow>\n    <sequenceFlow id=\"f3_reject\" name=\"椹冲洖\" sourceRef=\"gw1\" targetRef=\"rejectHandler\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${approved == false}</conditionExpression>\n    </sequenceFlow>\n    <sequenceFlow id=\"f_reject_back\" sourceRef=\"rejectHandler\" targetRef=\"deptAudit\" />\n    <sequenceFlow id=\"f4\" sourceRef=\"genContractTask\" targetRef=\"depositPayment\" />\n    <sequenceFlow id=\"f_deposit_to_audit\" sourceRef=\"depositPayment\" targetRef=\"depositAudit\" />\n    <sequenceFlow id=\"f_deposit_audit_result\" sourceRef=\"depositAudit\" targetRef=\"gw2\" />\n    <sequenceFlow id=\"f_deposit_pass\" name=\"閫氳繃\" sourceRef=\"gw2\" targetRef=\"balancePayment\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${approved == true}</conditionExpression>\n    </sequenceFlow>\n    <sequenceFlow id=\"f_deposit_reject\" name=\"椹冲洖\" sourceRef=\"gw2\" targetRef=\"depositPayment\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${approved == false}</conditionExpression>\n    </sequenceFlow>\n    <sequenceFlow id=\"f_balance_to_audit\" sourceRef=\"balancePayment\" targetRef=\"balanceAudit\" />\n    <sequenceFlow id=\"f_balance_audit_result