m.declaration.service.DocumentGenerationService\" />\r\n    \r\n    <!-- 杩斿洖鍙戣捣浜轰换鍔?-->\r\n    <userTask id=\"returnDocument\" name=\"鏂囦欢杩斿洖鍙戣捣浜篭" \r\n              flowable:assignee=\"${initiator}\">\r\n      <extensionElements>\r\n        <flowable:taskListener event=\"create\" delegateExpression=\"${taxRefundExecutionListener}\"></flowable:taskListener>\r\n      </extensionElements>\r\n    </userTask>\r\n    \r\n    <!-- 鎻愪氦鍙戠エ閫€绋庝俊鎭换鍔?-->\r\n    <userTask id=\"invoiceSubmit\" name=\"鎻愪氦鍙戠エ閫€绋庝俊鎭痋" \r\n              flowable:assignee=\"${initiator}\">\r\n      <extensionElements>\r\n        <flowable:taskListener event=\"create\" delegateExpression=\"${taxRefundExecutionListener}\"></flowable:taskListener>\r\n      </extensionElements>\r\n    </userTask>\r\n    \r\n    <!-- 璐㈠姟澶嶅浠诲姟 -->\r\n    <userTask id=\"financeFinalReview\" name=\"璐㈠姟澶嶅\" \r\n              flowable:candidateGroups=\"finance\">\r\n      <extensionElements>\r\n        <flowable:taskListener event=\"create\" delegateExpression=\"${taxRefundExecutionListener}\"></flowable:taskListener>\r\n      </extensionElements>\r\n    </userTask>\r\n    \r\n    <!-- 鏂囦欢褰掓。鏈嶅姟浠诲姟 -->\r\n    <serviceTask id=\"archiveDocument\" name=\"鏂囦欢褰掓。\" \r\n                 flowable:class=\"com.declaration.service.DocumentArchiveService\" />\r\n    \r\n    <!-- 缁撴潫浜嬩欢 -->\r\n    <endEvent id=\"endEvent\" name=\"缁撴潫\" />\r\n    \r\n    <!-- 娴佺▼杩炵嚎 -->\r\n    <sequenceFlow id=\"flow1\" sourceRef=\"startEvent\" targetRef=\"departmentSubmit\" />\r\n    <sequenceFlow id=\"flow2\" sourceRef=\"departmentSubmit\" targetRef=\"financeReview\" />\r\n    <sequenceFlow id=\"flow3\" sourceRef=\"financeReview\" targetRef=\"generateDocument\" />\r\n    <sequenceFlow id=\"flow4\" sourceRef=\"generateDocument\" targetRef=\"returnDocument\" />\r\n    <sequenceFlow id=\"flow5\" sourceRef=\"returnDocument\" targetRef=\"invoiceSubmit\" />\r\n    <sequenceFlow id=\"flow6\" sourceRef=\"invoiceSubmit\" targetRef=\"financeFinalReview\" />\r\n 