ersion=\"1.0\" encoding=\"UTF-8\"?>\n<definitions xmlns=\"http://www.omg.org/spec/BPMN/20100524/MODEL\" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\" xmlns:bpmndi=\"http://www.omg.org/spec/BPMN/20100524/DI\" xmlns:omgdc=\"http://www.omg.org/spec/DD/20100524/DC\" xmlns:omgdi=\"http://www.omg.org/spec/DD/20100524/DI\" xmlns:xsd=\"http://www.w3.org/2001/XMLSchema\" xmlns:flowable=\"http://flowable.org/bpmn\" targetNamespace=\"http://www.flowable.org/processdef\">\n  <process id=\"declarationProcess\" name=\"鐢虫姤瀹℃壒鍏ㄧ敓鍛藉懆鏈熸祦绋媆" isExecutable=\"true\">\n    <startEvent id=\"startEvent1\" name=\"鍚姩鐢虫姤\" flowable:initiator=\"starterId\" />\n    <userTask id=\"deptAudit\" name=\"閮ㄩ棬鍒濆\" flowable:candidateGroups=\"DEPT_MANAGER\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\" />\n      </extensionElements>\n    </userTask>\n    <exclusiveGateway id=\"gw1\" name=\"鍒濆缁撴灉\" />\n    <userTask id=\"rejectHandler\" name=\"椹冲洖淇敼\" flowable:assignee=\"${starterId}\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\" />\n      </extensionElements>\n    </userTask>\n    <serviceTask id=\"genContractTask\" name=\"鑷姩鐢熸垚鍏ㄥ鍗曡瘉\" flowable:delegateExpression=\"${declarationServiceTask}\" />\n    <parallelGateway id=\"gwParallelFork\" name=\"骞惰鍒嗘敮鍚姩\">\n      <extensionElements>\n        <flowable:executionListener event=\"end\" delegateExpression=\"${declarationTaskListener}\" />\n      </extensionElements>\n    </parallelGateway>\n    <userTask id=\"depositPayment\" name=\"涓婁紶瀹氶噾鍑瘉\" flowable:assignee=\"${starterId}\">\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${declarationTaskListener}\" />\n      </extensionElements>\n    </userTask>\n    <userTask id=\"depositAudit\" name=\"璐㈠姟纭瀹氶噾\" flowable:candidateGroups=\"FINANCE_MANAGER\">\n      <extensionElements>\n     